export class Invoice {
  isOverdue(today: Date) {
    return this.dueDate < today && !this.paidAt;
  }
}

export class UserPermission {
  canApprove(invoice: Invoice) {
    return this.roles.includes('approver') && invoice.total.cents < this.limit.cents;
  }
}

export class PayInvoice {
  constructor(private gateway: InvoiceGateway) {}

  execute(invoiceId: string) {
    return this.gateway.pay(invoiceId);
  }
}

export class ApproveInvoice {
  constructor(private invoices: InvoiceGateway) {}
  execute(invoice: Invoice, permission: UserPermission) {
    if (!permission.canApprove(invoice)) throw new Error('Forbidden');
    return this.invoices.approve(invoice.id);
  }
}

export function presentInvoice(invoice: Invoice): InvoiceView {
  return { id: invoice.id, statusLabel: invoice.isOverdue(new Date()) ? 'Vencida' : 'Em dia' };
}

@Component({ templateUrl: './invoice.page.html' })
export class InvoicePage {
  view = computed(() => presentInvoice(this.invoice()));
}
